-- в”Ђв”Ђ SalesScreen в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$SalesScreen is a sales gamification and performance management platform that turns CRM activity into real-time leaderboards, competitions, and rewards.$q$, short_description),
  pricing_model = COALESCE($q$Tiered, team-size-gated subscription priced per month$q$, pricing_model),
  starting_price = COALESCE($q$From $250 USD per month for the Scale plan, minimum 10 users$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Oslo, Norway$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SalesScreen Review 2026: Pricing, Features, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See how SalesScreen's Scale and Pro plans price out, what sales gamification features are included, and whether it fits your sales team's motivation strategy.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SalesScreen is a sales gamification and performance management platform headquartered in Oslo, Norway, with additional offices in Barcelona, Spain and New York City; more than a third of its revenue reportedly comes from the North American market. The company traces its roots to 2011, when it began as a consultancy called Dogu before pivoting into the dedicated sales gamification product now known as SalesScreen. The platform is designed to help sales managers keep reps motivated and focused by turning CRM activity data into real-time dashboards, leaderboards, and competitions; it connects natively to CRMs such as Salesforce and HubSpot so that calls, deals, and other sales activities sync automatically into the gamification layer. Core capabilities include customizable performance metrics and targets, an interactive social feed for celebrating wins, dozens of pre-built sales competitions and games, milestone and achievement recognition, a redeemable reward shop with physical prizes, and coaching or scorecard tools sold as an add-on for roughly 5 dollars per user per month on any plan. SalesScreen uses a tiered, team-size-gated pricing structure rather than a simple per-seat model: an Essentials tier is available as a 30-day free trial requiring no credit card, a Scale plan starts at 250 dollars per month for a minimum of 10 users, about 25 dollars per user per month, and is the most commonly recommended tier, a Pro plan starts at 675 dollars per month for a minimum of 15 users, about 45 dollars per user per month, and unlocks features like metric funnels, battles, and premium integrations, and an Enterprise plan offers custom pricing with a private database and advanced access management for larger organizations. SalesScreen is best suited to sales organizations of 10 or more reps, such as inside sales, field sales, and call center teams, that already use Salesforce or HubSpot and want to layer motivation, transparency, and recognition on top of their existing pipeline data rather than replace their CRM outright.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7';

