-- в”Ђв”Ђ Samvera Hyrax в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Samvera Hyrax is a free, open-source Ruby on Rails engine that gives libraries and archives a foundation for building digital repository applications.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Samvera Hyrax Review: Features, Pricing, and Use Cases$q$, seo_title),
  seo_meta_description = COALESCE($q$See what the open-source Samvera Hyrax digital repository framework offers libraries and archives, from metadata workflows to Valkyrie storage support.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Samvera Hyrax is a free, open-source Ruby on Rails engine that gives libraries, archives, and other cultural heritage and research institutions a ready-made foundation for building digital repository applications to manage, preserve, and provide access to digital collections. Hyrax was created in December 2016 as a consolidation of two earlier, overlapping Samvera community gems, Sufia and CurationConcerns, following community discussion at Hydra Connect 2016 about whether the two projects should merge. Hyrax itself sits within the broader Samvera community, which originated in September 2008 as a collaboration among Stanford University, the University of Virginia, the University of Hull, and the Fedora Commons project under the name the Hydra Project; the community adopted the new name Samvera, Icelandic for togetherness, in May 2017 to reflect its growth beyond the original Hydra-branded tooling. Hyrax is released under the Apache License 2.0 and is maintained collectively by the volunteer Samvera community rather than by a single vendor or company, so there is no pricing, sales process, or corporate headquarters associated with it; institutions typically need their own developers, or a hosting partner, to deploy and customize it. Architecturally, Hyrax provides common repository features out of the box, including deposit workflows, metadata editing, access control, batch operations, collections and works management, and a configurable public-facing discovery interface. More recent major versions, notably Hyrax 5, added support for the Valkyrie data mapper, decoupling the application from a hard dependency on the Fedora repository server so that institutions can choose different persistence and storage back ends. Because it is built specifically for repository and digital-collections use cases rather than general-purpose content management, Hyrax is best suited to academic libraries, archives, museums, and research data repositories that need standards-based metadata, persistent identifiers, and preservation-oriented storage, and it is typically evaluated alongside other Samvera-based tools like Hyku, a hosted, multi-tenant flavor of Hyrax, and other open-source repository platforms such as DSpace and Islandora.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f31da656-5abb-4ac5-8a10-1c4937d3ecce';

