-- в”Ђв”Ђ SANE Network Scanning в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$SANE, short for Scanner Access Now Easy, is a free, open-source API and driver framework that provides standardized access to scanners on Unix and Linux systems.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(1996, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SANE (Scanner Access Now Easy) Review: Features and Use Cases$q$, seo_title),
  seo_meta_description = COALESCE($q$Understand what the open-source SANE API offers for scanning on Linux and Unix, including backends, scanimage, and network scanning with saned.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SANE, an acronym for Scanner Access Now Easy, is a free and open-source application programming interface and driver framework that provides a standardized way for software on Unix and Unix-like operating systems, including Linux, BSD, and macOS, to access image scanners, still and video cameras, and frame grabbers. The project's first public release came on November 27, 1996, originated by David Mosberger-Tang together with early collaborators, after preliminary development work that had begun a few years earlier; the project has since been maintained by a volunteer community rather than a company. SANE's architecture separates hardware-specific backends, which speak directly to individual scanner models or families over USB, SCSI, or network connections, from generic frontends, the applications end users interact with; the reference command-line frontend, scanimage, and the network scanning daemon, saned, ship as part of the core sane-backends package, while graphical frontends such as XSane and xscanimage are developed and distributed separately. The saned network daemon allows a scanner physically attached to one machine to be shared and accessed remotely over a network, extending SANE's usefulness beyond a single desktop. SANE components are distributed under GPL and LGPL licenses, with some libraries having moved from the Library GPL to LGPL 2.1 over the years, consistent with its status as core open-source Unix infrastructure rather than a commercial product; it has no list price, subscription plans, company, or headquarters. Source code and issue tracking for the backends now live in a GitLab repository under the sane-project namespace, and SANE is packaged directly into essentially every major Linux distribution, making it the de facto standard scanning layer beneath higher-level tools like GIMP's scanner plugin, common print-and-scan utilities, and desktop scanning applications. SANE is best suited to Linux and Unix system administrators, distribution packagers, and developers who need a hardware-abstracted way to add scanning support to an application, rather than end users looking for a polished consumer scanning app, though tools like XSane provide a usable graphical front end for everyday scanning tasks.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'bab3c6db-9b5a-484e-b9f3-7c8e256e957e';

