INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Sales Cadences$q$, $q$Multi-step, multi-channel outreach sequences combining email, phone calls, and social touches to standardize prospecting.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Built-in Dialer$q$, $q$Click-to-call calling directly inside the platform with call recording and logging.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Conversation Intelligence$q$, $q$AI-driven call recording, transcription, and analysis that surfaces talk tracks, objections, and coaching moments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Deal Management$q$, $q$Deal Rooms and Deal Insights that centralize buyer engagement and deal risk signals.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Email Tracking and Templates$q$, $q$Open and click tracking, dynamic personalization, and a shared template library for reps.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Forecasting and Analytics$q$, $q$Pipeline and revenue forecasting dashboards, expanded through the Clari integration after the December 2025 merger.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$AI Prioritization$q$, $q$AI-suggested next actions that tell reps who to contact and when, based on buyer engagement signals.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$CRM and Tooling Integrations$q$, $q$Native, two-way sync with Salesforce, Microsoft Dynamics, HubSpot, and other CRMs plus a wide app marketplace.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Deep, mature feature set for structured, repeatable outbound sales processes across email, calls, and social$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Conversation intelligence and deal insight tools give managers visibility into rep and deal health, not just activity counts$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Strong native integrations with Salesforce and other major CRMs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Post-merger roadmap with Clari adds enterprise-grade forecasting on top of engagement data$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Pricing is not published and requires a sales conversation, making cost comparison difficult for buyers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Third-party buying data suggests per-seat costs and add-ons like the dialer or Conversations can add up quickly for larger teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Steeper learning curve and implementation effort than lightweight, self-serve sales tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Best value is realized by larger sales organizations, so it can be costly for very small teams$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$What is Salesloft used for?$q$, $q$Salesloft is a sales engagement platform used by B2B sales teams to run structured outbound prospecting cadences across email and phone, track buyer engagement, record and analyze sales calls, manage deals, and forecast revenue.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$How much does Salesloft cost?$q$, $q$Salesloft does not publish list pricing. It sells custom, quote-based subscriptions typically organized into Essentials, Advanced, and Premier tiers, with per-seat costs that third-party sources report ranging from roughly 75 dollars to over 200 dollars per user per month depending on tier, contract term, and add-ons.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$When was Salesloft founded?$q$, $q$Salesloft was incorporated in September 2011 in Atlanta, Georgia, by Kyle Porter and David Cummings.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Did Salesloft merge with another company?$q$, $q$Yes. Salesloft completed a merger with revenue intelligence company Clari on December 3, 2025, with Clari's Steve Cox becoming CEO of the combined organization.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$What is Salesloft's Conversation Intelligence feature?$q$, $q$It is an AI-powered call recording and analysis tool that transcribes sales calls, highlights talk tracks and objections, and helps managers coach reps based on real conversation data.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Who are Salesloft's main competitors?$q$, $q$Salesloft competes primarily with Outreach in the sales engagement category, along with tools like Apollo.io and Groove; its expanded scope after the Clari merger also brings it into competition with dedicated forecasting and revenue intelligence vendors.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Does Salesloft integrate with Salesforce?$q$, $q$Yes, Salesloft offers native, two-way integration with Salesforce, along with integrations for Microsoft Dynamics, HubSpot, and other CRMs.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Is Salesloft suitable for small businesses?$q$, $q$Salesloft is generally built for mid-market and enterprise B2B sales teams that need a structured outbound process; its quote-based pricing and feature depth make it less cost-effective for very small teams compared with lighter, self-serve sales tools.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Outbound Prospecting at Scale$q$, $q$Sales development teams use Salesloft to build and run multi-touch cadences across email, phone, and social channels so every rep follows a consistent, measurable prospecting process.$q$, $q$SDR and BDR teams at B2B companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Deal and Pipeline Visibility$q$, $q$Account executives and sales managers use Deal Rooms and Deal Insights inside Salesloft to track buyer engagement on active opportunities and flag deals at risk before they stall.$q$, $q$Mid-market and enterprise sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Call Coaching and Revenue Forecasting$q$, $q$Sales leaders use Conversation Intelligence recordings alongside forecasting dashboards, increasingly powered by the Clari integration, to coach reps on call performance and improve forecast accuracy.$q$, $q$Sales managers and revenue operations leaders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Essentials$q$, $q$Custom pricing - contact sales$q$, $q$Annual contract, quote-based$q$, NULL, $q$["Sales cadences across email and phone","Built-in dialer and email tracking","Core reporting and activity dashboards","Salesforce or HubSpot integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Advanced$q$, $q$Custom pricing - contact sales$q$, $q$Annual contract, quote-based$q$, NULL, $q$["Everything in Essentials","Conversation intelligence for call recording and analysis","Deal management and Deal Insights","Expanded automation and workflow tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$Premier$q$, $q$Custom pricing - contact sales$q$, $q$Annual contract, quote-based$q$, NULL, $q$["Everything in Advanced","Advanced forecasting and analytics","AI-driven prioritization","Priority support and expanded admin controls"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Salesloft is a sales engagement and revenue orchestration platform founded in 2011 in Atlanta, Georgia, by Kyle Porter and David Cummings. It gives B2B sales teams a single workspace to run outbound prospecting cadences, track buyer engagement across email and calls, manage deals, and forecast revenue, and it expanded its scope significantly after completing a merger with revenue intelligence company Clari in December 2025.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Salesloft organizes outreach into cadences, multi-step sequences that blend email, phone calls, and social touches so reps follow a consistent, repeatable process instead of ad hoc outreach.$q$, $q$Beyond prospecting, the platform adds conversation intelligence for call recording and coaching, Deal Rooms and Deal Insights for pipeline visibility, and AI-driven next-action prioritization, with native two-way integrations into Salesforce, Microsoft Dynamics, and HubSpot.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0f4afdee-5f6e-4f90-abf7-5fd32937393b', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Salesloft does not publish list pricing on its website; all plans are quoted individually based on seat count, contract length, and selected modules across three commonly cited tiers, Essentials, Advanced, and Premier.$q$, $q$Third-party buyer intelligence sources report per-seat costs ranging from roughly 75 dollars to over 200 dollars per user per month depending on tier and add-ons, with extras such as the dialer or Conversations billed separately and capable of adding meaningfully to total contract value.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Deal Pipeline Management$q$, $q$Visual, customizable pipelines for tracking deals from lead to close.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Native Calling and Texting$q$, $q$Built-in power dialer, voicemail drop, SMS, and call transcription without a separate telephony add-on.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Sandy AI Assistant$q$, $q$Built-in AI assistant plus newer AI agents that help automate lead qualification, meeting booking, and workflow triggers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Workflow Automation$q$, $q$Smart flow automation credits that trigger emails, tasks, and notifications based on deal or contact activity.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Email Sequences and Tracking$q$, $q$Automated multi-step email sequences with open and click tracking.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Team Inbox and Ticketing$q$, $q$Shared inbox and basic support ticketing for teams that combine sales and customer service.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Custom Dashboards and Reporting$q$, $q$Configurable reports and goal-tracking dashboards available from the Pro tier up.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Meeting Scheduler$q$, $q$Built-in scheduling links for booking meetings directly from email or the CRM.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Native calling, texting, and power dialer functionality included without a separate paid add-on at higher tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Competitive per-user pricing starting at 23 dollars per month compared with many enterprise CRMs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Built-in AI assistant and automation tools aimed at reducing manual data entry$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$15-day free trial with full feature access and no credit card required$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Entry-level Basic plan lacks sequences, team inbox, and AI features, which are gated to Pro and above$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Power dialer and voicemail drop are limited to the Business tier and above$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Smart flow automation is credit-limited per plan, which can constrain heavy automation users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Smaller third-party integration ecosystem than larger CRMs like Salesforce or HubSpot$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$What is Salesmate used for?$q$, $q$Salesmate is an AI-powered CRM used by small and mid-sized businesses to manage sales pipelines, automate outreach, place calls and texts, and handle basic customer support from one platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$How much does Salesmate cost?$q$, $q$Salesmate starts at 23 dollars per user per month for the Basic plan, with Pro at 39 dollars, Business at 63 dollars per user per month billed annually (79 dollars billed monthly), and a custom-quoted Enterprise tier.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Who owns Salesmate?$q$, $q$Salesmate is a product of Rapidops Inc., founded in 2016 by Samir Motwani and Dipesh Patel, headquartered in Charlotte, North Carolina.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Does Salesmate include a built-in dialer?$q$, $q$Yes, calling, texting, power dialing, and voicemail drop are built into the Business and Enterprise plans, with basic calling and email available on lower tiers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Does Salesmate offer a free trial?$q$, $q$Yes, Salesmate offers a 15-day free trial with full access to features and no credit card required.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$What is Sandy AI?$q$, $q$Sandy AI is Salesmate's built-in AI assistant, available from the Pro plan up, complemented by newer AI agents for tasks like lead qualification and meeting booking.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Does Salesmate support annual billing discounts?$q$, $q$Yes, annual billing saves up to approximately 20 percent compared with monthly billing.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$What does the Enterprise plan include?$q$, $q$The Enterprise plan adds audit logs, dedicated onboarding and account management, IP restriction, quarterly business reviews, and 24/7 support on top of custom pricing.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Small Business Sales Pipeline Management$q$, $q$Small sales teams use Salesmate's visual pipelines and built-in calling to track deals and reach prospects without stitching together separate CRM and phone tools.$q$, $q$Small and mid-sized B2B sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Combined Sales and Support Workflows$q$, $q$Teams that need light customer support alongside sales use Salesmate's team inbox and ticketing tools to manage both from a single record.$q$, $q$Small businesses with combined sales and support functions$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Automated Outreach Sequences$q$, $q$Sales reps use email sequences, smart flow automation, and the meeting scheduler to reduce manual follow-up work and book more meetings.$q$, $q$SMB sales and business development reps$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Basic$q$, $q$$23 USD per user per month$q$, $q$Monthly or annual$q$, NULL, $q$["Contact and company management","Deal pipeline management","Email sync, templates, and tracking","Meeting scheduler","Standard dashboards and reports","5,000 smart flow credits per user per month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Pro$q$, $q$$39 USD per user per month$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Basic","Email sequences","Team inbox and ticketing","Custom dashboards with goal tracking","Single sign-on and Sandy AI assistant","10,000 smart flow credits per user per month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Business$q$, $q$$63 USD per user per month billed annually, $79 billed monthly$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Pro","Power dialer and voicemail drop","Custom modules and surveys","Advanced goal management","15,000 smart flow credits per user per month"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$Enterprise$q$, $q$Custom pricing - contact sales$q$, $q$Annual contract$q$, NULL, $q$["Everything in Business","Audit logs and dedicated onboarding","Dedicated account manager","IP restriction and quarterly business reviews","24/7 support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Salesmate is an AI-powered CRM built by Rapidops Inc., founded in 2016 and headquartered in Charlotte, North Carolina. It combines sales pipeline management, marketing automation, and light customer support tools in one platform aimed at small and mid-sized businesses.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Salesmate natively bundles calling, texting, power dialing, and voicemail drop into its higher-tier plans, avoiding the need for a separate telephony add-on that many competing CRMs require.$q$, $q$The platform also includes deal pipeline management, email sequences, a meeting scheduler, workflow automation credits called smart flows, and an AI layer built around the Sandy AI assistant and newer AI agents for lead qualification and meeting booking.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7986cf0f-17ab-4528-acea-8231ffbd3ebc', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Salesmate offers four tiers: Basic at 23 dollars per user per month, Pro at 39 dollars, Business at 63 dollars per user per month billed annually or 79 dollars billed monthly, and a custom-quoted Enterprise tier.$q$, $q$Annual billing saves up to roughly 20 percent compared with monthly billing, and a 15-day free trial with full feature access is available with no credit card required.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Real-Time Leaderboards and Dashboards$q$, $q$Live displays of rep and team performance pulled automatically from connected CRMs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Sales Competitions$q$, $q$Pre-built and customizable competitions and games that run over set time windows to drive short-term motivation.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Achievements and Milestones$q$, $q$Automated recognition for hitting personal or team milestones, shown in an interactive social feed.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Reward Shop$q$, $q$A redeemable rewards catalog where reps can exchange earned points for real prizes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Metric Targets and Funnels$q$, $q$Configurable targets on tracked metrics and funnel views for sales activities, available from Scale and Pro tiers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Battles$q$, $q$Head-to-head or team-versus-team competitions available on the Pro plan and above.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Coaching and Scorecards Add-on$q$, $q$An optional add-on, priced separately per user, for structured coaching and performance scorecards.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Native CRM Integrations$q$, $q$Real-time sync with Salesforce and HubSpot, plus additional premium integrations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Deep, purpose-built gamification feature set beyond simple leaderboards, including competitions, achievements, and a physical reward shop$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Native, real-time integrations with Salesforce and HubSpot keep dashboards current without manual data entry$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Free 30-day Essentials trial with no credit card required$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Global presence with offices in Oslo, Barcelona, and New York supporting customers across regions$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Paid plans are gated by minimum team size, 10 users for Scale and 15 for Pro, making it less economical for very small teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Advanced features like metric funnels, battles, and premium integrations are locked to higher tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Coaching and scorecards require a separate per-user add-on rather than being included$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Enterprise-level features like a private database require custom Enterprise pricing$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$What is SalesScreen used for?$q$, $q$SalesScreen is a sales gamification and performance management platform that turns CRM activity data into real-time leaderboards, competitions, and rewards to keep sales teams motivated and focused.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$How much does SalesScreen cost?$q$, $q$SalesScreen's Scale plan starts at 250 dollars per month for a minimum of 10 users, and the Pro plan starts at 675 dollars per month for a minimum of 15 users; an Essentials tier is available as a free 30-day trial, and Enterprise pricing is custom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Where is SalesScreen based?$q$, $q$SalesScreen is headquartered in Oslo, Norway, with additional offices in Barcelona, Spain and New York City.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$When was SalesScreen founded?$q$, $q$SalesScreen traces its origins to 2011, when it began as a consultancy called Dogu before pivoting into the dedicated sales gamification product now known as SalesScreen.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Does SalesScreen integrate with Salesforce and HubSpot?$q$, $q$Yes, SalesScreen offers native integrations with both Salesforce and HubSpot that sync sales data and activity in real time.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Is there a free trial for SalesScreen?$q$, $q$Yes, the Essentials tier is available as a 30-day free trial with no credit card required.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$What is the SalesScreen Coaching and Scorecards add-on?$q$, $q$It is an optional add-on available on any plan for roughly 5 dollars per user per month that adds structured coaching tools and performance scorecards.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$What is the minimum team size for SalesScreen's paid plans?$q$, $q$The Scale plan requires at least 10 users and the Pro plan requires at least 15 users.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Motivating Distributed Sales Teams$q$, $q$Sales managers use SalesScreen's real-time dashboards and competitions to keep remote or distributed reps engaged and aligned on the same goals.$q$, $q$Inside sales and remote sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Running Short-Term Sales Contests$q$, $q$Sales leaders launch time-boxed competitions and battles tied to specific metrics, such as new opportunities created or calls made, to drive a short-term push.$q$, $q$Sales managers running incentive campaigns$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Recognizing Performance Without Manual Tracking$q$, $q$Teams use automated achievements and the reward shop, fed directly by Salesforce or HubSpot data, to recognize top performers without manually tracking milestones in a spreadsheet.$q$, $q$RevOps and sales enablement teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Essentials$q$, $q$Free 30-day trial$q$, $q$Trial$q$, NULL, $q$["Real-time dashboards","Interactive activity feed","Basic competitions","Up to 4 tracked metrics","Up to 10 achievements"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Scale$q$, $q$From $250 USD per month, minimum 10 users$q$, $q$Monthly$q$, NULL, $q$["Up to 8 tracked metrics","Targets on metrics","Unlimited achievements","Premium integrations available as add-on"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Pro$q$, $q$From $675 USD per month, minimum 15 users$q$, $q$Monthly$q$, NULL, $q$["Everything in Scale","Metric funnels","Battles","Premium integrations included","Advanced access management"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$Enterprise$q$, $q$Custom pricing - contact sales$q$, $q$Annual contract$q$, NULL, $q$["Everything in Pro","Private database","Custom security and access controls"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$SalesScreen is a sales gamification and performance management platform headquartered in Oslo, Norway, with roots dating back to 2011 as a consultancy called Dogu, plus offices in Barcelona and New York. It helps sales managers keep reps motivated by turning CRM activity into real-time dashboards, competitions, and rewards.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$SalesScreen syncs natively with Salesforce and HubSpot so that calls, deals, and other activities feed real-time leaderboards, achievements, and an interactive social feed without manual data entry.$q$, $q$Higher tiers add configurable metric targets, metric funnels, head-to-head battles, and a redeemable reward shop, with coaching and scorecards available as a separate add-on.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bfe49e03-fbc6-4c28-83dc-fa4e4e5939d7', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SalesScreen's Essentials tier is a free 30-day trial, the Scale plan starts at 250 dollars per month for a minimum of 10 users, and the Pro plan starts at 675 dollars per month for a minimum of 15 users, with a custom-quoted Enterprise tier above that.$q$, $q$An optional Coaching and Scorecards add-on is available on any plan for roughly 5 dollars per user per month.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Multi-Frontend Architecture$q$, $q$One shared backend powers desktop, web, command-line, and text user interface frontends from the same account.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$End-to-End Encryption$q$, $q$Support for OMEMO and OpenPGP encryption for private conversations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Audio and Video Calls$q$, $q$Direct and group audio and video calling built on XMPP extensions.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Blogging and Microblogging$q$, $q$PubSub-based blogging and microblogging features built into the same platform as messaging.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$File Sharing$q$, $q$Encrypted file transfer between contacts.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$ActivityPub Gateway$q$, $q$A bridge that lets Libervia accounts interact with Fediverse services such as Mastodon.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Legacy Network Gateways$q$, $q$Bridges to IRC and email so XMPP users can reach contacts on other networks.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Decentralized Issue Tracking$q$, $q$Built-in tools for managing tasks and issue trackers over XMPP PubSub.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Fully free, open-source, and federated, with no vendor lock-in or subscription cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Unusually broad feature set for an XMPP client, spanning messaging, blogging, calls, and file sharing in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Multi-frontend design lets the same account be used from desktop, web, command-line, or mobile-style interfaces$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Backed by NLnet and NGI funding, supporting continued development of privacy features$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Long, largely solo-led development history means a smaller contributor base than major messaging platforms$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Smaller user base than mainstream chat apps, so network effects and contact discovery are limited$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Documentation and interface are primarily oriented toward technically comfortable users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Now branded as Libervia, which can cause confusion for people searching under the older Salut Г  Toi name$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$What is Salut Г  Toi?$q$, $q$Salut Г  Toi, now officially known as Libervia, is a free, decentralized, multi-frontend communication platform built on the XMPP standard, supporting instant messaging, blogging, file sharing, and audio/video calls.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Is Salut Г  Toi free?$q$, $q$Yes, it is free and open-source software released under the GNU Affero General Public License version 3 or later.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Who develops Salut Г  Toi?$q$, $q$It has been developed primarily by French developer Jerome Poisson, known as Goffi, since around 2008, with contributions from Adrien Cossa and funding support from NLnet and the NGI initiative in recent years.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$What does Salut Г  Toi have to do with Libervia?$q$, $q$Salut Г  Toi was rebranded as Libervia; both names refer to the same underlying project and codebase.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$What frontends does Salut Г  Toi support?$q$, $q$It supports desktop, web, command-line, and text user interface frontends, all sharing the same backend and account.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Does Salut Г  Toi support encryption?$q$, $q$Yes, it supports end-to-end encryption via both OMEMO and OpenPGP.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Can Salut Г  Toi communicate with other networks?$q$, $q$Yes, through gateways it can bridge to IRC, email, and, via an ActivityPub gateway, Fediverse platforms such as Mastodon.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Does Salut Г  Toi require a company account or subscription?$q$, $q$No, it is a community and association-run free software project with no company, pricing plans, or subscription requirement.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Federated Personal Messaging$q$, $q$Privacy-conscious individuals use Salut Г  Toi/Libervia as their primary XMPP client for encrypted one-to-one and group messaging without depending on a centralized provider.$q$, $q$Privacy-focused individual users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Combined Blogging and Chat$q$, $q$Users who want to publish blog or microblog posts and chat from the same federated identity use its integrated PubSub-based blogging features.$q$, $q$Independent bloggers and Fediverse users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Cross-Network Bridging$q$, $q$Technical users bridge XMPP conversations to IRC, email, or ActivityPub-based networks to consolidate communication in one client.$q$, $q$Developers and free-software community members$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full access to all frontends: desktop, web, command-line, and text user interface","End-to-end encryption via OMEMO and OpenPGP","Blogging, file sharing, and audio/video calls","No account fees, self-hostable via any XMPP server"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Salut Г  Toi, now officially known as Libervia, is a free, decentralized communication platform built on the XMPP standard, developed since around 2008 primarily by French developer Jerome Poisson, known as Goffi, with recent funding from NLnet and the NGI initiative.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Its defining feature is a shared backend that powers many frontends, desktop, web, command-line, and text user interface, from the same account, going well beyond instant messaging to include blogging, encrypted file sharing, and audio/video calls.$q$, $q$Gateways let Libervia bridge to IRC, email, and, through an ActivityPub gateway, Fediverse platforms such as Mastodon, while OMEMO and OpenPGP provide end-to-end encryption for private conversations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0da45043-d5e4-43e0-b1d2-e47565c3ce95', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Salut Г  Toi/Libervia is entirely free and open source, released under the GNU Affero General Public License version 3 or later, with no subscription plans, company, or sales process; it can be self-hosted or used with any compatible XMPP server.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$WebSocket-Based Chat Server$q$, $q$Core sama-server built on uWebSockets.js for high-throughput, low-latency real-time messaging.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$End-to-End Encryption$q$, $q$Built-in encryption support for private conversations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Clustering and High Availability$q$, $q$Native clustering support for horizontal scaling and uptime.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Multi-Device Support$q$, $q$Sessions and message sync across multiple devices per user.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Push Notifications$q$, $q$Built-in push notification support for mobile and web clients.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Prebuilt Clients$q$, $q$Official React web client and Flutter mobile client available alongside the server.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Admin Dashboard$q$, $q$A dedicated, MIT-licensed administrative dashboard for managing deployments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$REST and WebSocket APIs$q$, $q$Documented APIs for building custom chat experiences on top of the server.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Fully open source and self-hostable, giving developers complete control over data and infrastructure$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Comes with a full stack out of the box: server, web client, mobile client, and admin dashboard$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Built on modern, high-performance WebSocket tooling with uWebSockets.js$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Public hosted demo at app.samacloud.io makes it easy to evaluate before self-hosting$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$No public company information, founding date, or headquarters, making vendor due diligence harder$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Smaller community and GitHub following compared with larger open-source chat projects$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Self-hosting requires developer resources to deploy, secure, and maintain the server and clustering setup$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Documentation is comparatively lightweight versus established commercial chat APIs$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$What does SAMA stand for?$q$, $q$SAMA stands for Simple but Advanced Messaging Alternative, an open-source chat server for mobile and web applications.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Is SAMA free?$q$, $q$Yes, SAMA is free, open-source software that can be self-hosted; a public hosted demo is also available at app.samacloud.io.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$What is SAMA built with?$q$, $q$The core sama-server is built in JavaScript on uWebSockets.js, with an official React-based web client and a Flutter-based mobile client.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Does SAMA support encryption?$q$, $q$Yes, SAMA includes end-to-end encryption support along with clustering for high availability.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Who maintains SAMA?$q$, $q$SAMA is maintained by the SAMA-Communications organization on GitHub, which publishes the server, clients, and an admin dashboard.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Can I test SAMA without installing it?$q$, $q$Yes, the full SAMA stack can be tested against the public cloud instance at app.samacloud.io.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Does SAMA support multiple devices per user?$q$, $q$Yes, SAMA supports multi-device sessions along with push notifications.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Where can I find SAMA's API documentation?$q$, $q$SAMA's REST and WebSocket API documentation is published at docs.samacloud.io.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Embedding Chat in Mobile Apps$q$, $q$Developers use SAMA's server and Flutter client to add real-time chat to a mobile app without depending on a proprietary chat API.$q$, $q$Mobile app developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Self-Hosted Team or Community Chat$q$, $q$Organizations that need to keep chat data on their own infrastructure deploy sama-server with clustering for reliability.$q$, $q$Privacy-focused organizations and self-hosting enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Rapid Prototyping with a Hosted Demo$q$, $q$Teams evaluate SAMA's features against the public app.samacloud.io instance before committing to a self-hosted deployment.$q$, $q$Engineering teams evaluating chat infrastructure$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$Self-Hosted / Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full sama-server source code","React web client and Flutter mobile client","Clustering and multi-device support","Admin dashboard included"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$SAMA, short for Simple but Advanced Messaging Alternative, is a free, open-source chat server maintained by the SAMA-Communications organization on GitHub, built on uWebSockets.js for high-throughput, low-latency real-time messaging.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The stack includes the core sama-server, a React-based web client, a Flutter-based mobile client, and an MIT-licensed admin dashboard, with end-to-end encryption, clustering for high availability, multi-device sessions, and push notifications built in.$q$, $q$Developers can evaluate the full stack against a public hosted demo at app.samacloud.io before deciding to self-host, and REST and WebSocket API documentation is published at docs.samacloud.io.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fb62ae2f-72bd-4969-b944-dde6d7d56470', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SAMA is free and open source with no published pricing tiers; it is designed to be self-hosted, and a public cloud demo instance is available for testing at no cost.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$SMB/CIFS File and Print Sharing$q$, $q$Lets Unix and Linux systems share files and printers with Windows clients and vice versa.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Active Directory Domain Controller$q$, $q$Samba 4.x can act as a full Active Directory domain controller, including Kerberos and LDAP services.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Windows Domain Member Support$q$, $q$Allows Linux servers to join an existing Windows Active Directory domain as a member server.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$NT4-Style Domain Control$q$, $q$Legacy support for classic Windows NT-style domain control for older environments.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Cross-Platform Interoperability$q$, $q$Works across Linux, BSD, macOS, and Windows, making it a common bridge in mixed-OS networks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$GPLv3 and LGPLv3 Licensing$q$, $q$Released under GPLv3 or later, and LGPLv3 or later for some libraries, ensuring the code remains free and open.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Command-Line and Daemon Tooling$q$, $q$Includes smbd, nmbd, winbindd, and command-line utilities for configuration, testing, and diagnostics.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Wide Distribution Support$q$, $q$Packaged directly into virtually every major Linux and BSD distribution.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Free and open source with no licensing cost, even for enterprise-scale deployments$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Mature, battle-tested codebase in continuous development since 1992$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Full Active Directory domain controller capability, not just basic file sharing$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Packaged into essentially every Linux and Unix distribution, so installation is straightforward$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Configuration and Active Directory setup can be complex for administrators unfamiliar with Windows networking internals$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$No commercial support organization by default; enterprise support requires third-party vendors or distribution-level contracts$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$SMB protocol version compatibility issues can arise with very old or very new Windows clients$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$As a community project, release cadence and documentation quality can vary compared with a commercial vendor$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$What is Samba software used for?$q$, $q$Samba is used to let Unix and Linux systems share files and printers with Windows computers and to interoperate with, or replace, Windows Active Directory domain controllers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Is Samba free?$q$, $q$Yes, Samba is free and open-source software licensed under the GNU General Public License version 3 or later.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Who created Samba?$q$, $q$Andrew Tridgell wrote the first version of Samba in December 1991 and January 1992 while a PhD student at the Australian National University; the project has since been maintained by the volunteer-led Samba Team.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Where does the name Samba come from?$q$, $q$Tridgell found the name by running the Unix grep command against the system dictionary looking for words containing the letters S, M, and B in that order, referencing the SMB protocol it implements.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Can Samba act as an Active Directory domain controller?$q$, $q$Yes, since the Samba 4.x series, Samba can function as a full Active Directory domain controller, not just a file and print server.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$What license does Samba use?$q$, $q$Samba is licensed under GPLv3 or later, having moved from GPLv2, with some libraries under LGPLv3 or later.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Does Samba work on macOS and BSD?$q$, $q$Yes, Samba runs on Linux, the BSDs, macOS, and other Unix-like systems in addition to being usable from Windows clients.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Is there a company behind Samba?$q$, $q$No, Samba is maintained by the volunteer, global Samba Team along with contributions and funding from various companies and organizations rather than a single commercial vendor.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Windows-Linux File Sharing$q$, $q$System administrators use Samba to let Linux file servers share directories and printers with Windows desktop clients on the same network.$q$, $q$Systems administrators in mixed-OS environments$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Active Directory Domain Controller Replacement$q$, $q$Organizations deploy Samba 4.x as a full Active Directory domain controller, avoiding a Windows Server license for core directory services.$q$, $q$IT administrators managing Windows domains on Linux infrastructure$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Cross-Platform Print Serving$q$, $q$Businesses use Samba to centralize printer sharing so both Linux and Windows machines can print through the same server.$q$, $q$Small business and enterprise IT teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full SMB/CIFS file and print sharing","Active Directory domain controller mode","Domain member and NT4-style domain control","Included in virtually every Linux/Unix distribution"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Samba is a free, open-source implementation of the SMB/CIFS protocol, originated by Andrew Tridgell in December 1991 and January 1992 at the Australian National University, and maintained since May 1996 by the volunteer-led Samba Team.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Samba lets Unix and Linux systems share files and printers with Windows clients and, since the 4.x series, can act as a full Active Directory domain controller with Kerberos and LDAP services, not just a basic file server.$q$, $q$It also supports classic domain member and NT4-style domain control for legacy environments, and it ships packaged into essentially every major Linux and BSD distribution.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('592933ba-3f90-4b7b-9d93-73fb6b1fd373', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Samba is entirely free and open source, licensed under the GNU General Public License version 3 or later, with LGPLv3 or later covering some libraries; there is no company, subscription, or license fee.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Deposit and Metadata Workflows$q$, $q$Configurable deposit forms and metadata schemas for describing digital objects and collections.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Works and Collections Model$q$, $q$Built-in data model for organizing individual works into collections with relationships between items.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Access Control$q$, $q$Role- and group-based permissions for controlling who can view, edit, or manage repository content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Batch Operations$q$, $q$Tools for bulk-editing metadata and managing large sets of objects at once.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Configurable Discovery Interface$q$, $q$A public-facing search and browse interface that institutions can customize and brand.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Valkyrie Data Mapper Support$q$, $q$Since Hyrax 5, a decoupled persistence layer that removes the hard dependency on the Fedora repository server.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Samvera Ecosystem Compatibility$q$, $q$Interoperates with other Samvera community tools and gems, including the multi-tenant Hyku distribution.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Apache 2.0 Licensing$q$, $q$Fully open-source licensing that allows institutions to freely deploy, modify, and extend the codebase.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Free, open-source, and purpose-built for library and archive digital repository needs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Backed by an active, multi-institution community, Samvera, rather than a single vendor$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Flexible persistence options since Hyrax 5 removed the hard Fedora dependency via Valkyrie$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Proven at scale across many academic and cultural heritage institutions worldwide$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Requires in-house Ruby on Rails development expertise or a hosting partner to deploy and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$No official pricing or vendor support line, since it is entirely community-maintained$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Setup and metadata modeling can be complex for institutions without prior repository experience$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Feature roadmap and release cadence depend on volunteer community capacity rather than a dedicated product team$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$What is Samvera Hyrax?$q$, $q$Samvera Hyrax is a free, open-source Ruby on Rails engine that provides libraries, archives, and research institutions with a foundation for building digital repository applications.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$When was Hyrax created?$q$, $q$Hyrax was created in December 2016 as a consolidation of two earlier Samvera community gems, Sufia and CurationConcerns.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$What license does Hyrax use?$q$, $q$Hyrax is released under the Apache License 2.0.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$What is the Samvera community?$q$, $q$Samvera is a global community of libraries, archives, and technologists that maintains Hyrax and related repository tools; it originated in 2008 as the Hydra Project and was renamed Samvera, Icelandic for togetherness, in May 2017.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Does Hyrax require Fedora?$q$, $q$Not necessarily; since Hyrax 5, the framework supports the Valkyrie data mapper, which decouples the application from a hard dependency on the Fedora repository server.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Is there a hosted version of Hyrax?$q$, $q$Institutions can self-host Hyrax or use Hyku, a multi-tenant Samvera distribution built on Hyrax, or work with third-party hosting partners.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Who uses Samvera Hyrax?$q$, $q$Academic libraries, archives, museums, and research data repositories use Hyrax to manage and provide access to digital collections.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Is Hyrax free to use?$q$, $q$Yes, Hyrax is free, open-source software with no licensing cost, though institutions typically need developer resources to deploy and customize it.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Institutional Digital Repositories$q$, $q$Academic libraries use Hyrax to build institutional repositories for theses, research data, and digitized special collections.$q$, $q$Academic and research libraries$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Archival Collections Access$q$, $q$Archives and museums use Hyrax's works-and-collections model to describe, organize, and provide public access to digitized archival materials.$q$, $q$Archives and museums$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Multi-Tenant Repository Hosting$q$, $q$Consortia and hosting providers build on Hyrax via the Hyku distribution to offer repository-as-a-service to multiple smaller institutions.$q$, $q$Library consortia and repository hosting providers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full Hyrax Ruby on Rails engine source code","Works, collections, and access control model","Valkyrie data mapper support in Hyrax 5 and later","Apache 2.0 license, free to modify and deploy"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Samvera Hyrax is a free, open-source Ruby on Rails engine, created in December 2016 by consolidating the earlier Sufia and CurationConcerns gems, that gives libraries and archives a foundation for building digital repository applications. It is maintained by the Samvera community, which originated in 2008 as the Hydra Project and was renamed Samvera in May 2017.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hyrax provides deposit and metadata workflows, a works-and-collections data model, role-based access control, batch operations, and a configurable public discovery interface out of the box.$q$, $q$Since Hyrax 5, the framework supports the Valkyrie data mapper, removing the hard dependency on the Fedora repository server so institutions can choose their own persistence and storage back ends.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f31da656-5abb-4ac5-8a10-1c4937d3ecce', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Hyrax is free and open source under the Apache License 2.0, with no vendor pricing; institutions typically need in-house Ruby on Rails developers or a hosting partner to deploy and maintain it.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Standardized Scanner API$q$, $q$A common programming interface that applications use to talk to scanners without needing device-specific code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Hardware Backends$q$, $q$Dedicated backend drivers for hundreds of scanner models across USB, SCSI, and network connections.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$scanimage Command-Line Frontend$q$, $q$A flexible command-line tool for scanning to PNM, TIFF, and other formats, included in sane-backends.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$saned Network Daemon$q$, $q$A network scanning daemon that lets a scanner attached to one machine be shared and accessed remotely.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Graphical Frontends$q$, $q$Separately distributed graphical applications such as XSane and xscanimage built on the SANE API.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$GPL and LGPL Licensing$q$, $q$Backends and tools distributed under GPL, with some libraries under LGPL, keeping the stack fully open.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Broad Linux Distribution Support$q$, $q$Packaged into essentially every major Linux distribution as the default scanning layer.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Application Integration$q$, $q$Underpins scanning support in tools like GIMP's scanner plugin and common desktop print-and-scan utilities.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Free, open-source, and installed by default across nearly all major Linux distributions$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Broad hardware support through hundreds of community-maintained backend drivers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Network scanning support via saned allows shared scanners across a network$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Long track record of stability as core Unix/Linux scanning infrastructure since 1996$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$No official company, support contract, or guaranteed response time for driver issues$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Backend support for brand-new scanner models can lag behind vendor Windows and macOS driver releases$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Command-line and API-level tools require more technical comfort than typical consumer scanning software$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Documentation is spread across the project website, man pages, and distribution wikis rather than centralized$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$What does SANE stand for?$q$, $q$SANE stands for Scanner Access Now Easy, an open-source API for accessing scanners and imaging hardware on Unix and Linux systems.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Is SANE free?$q$, $q$Yes, SANE is free and open-source software distributed under GPL and LGPL licenses.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$When was SANE first released?$q$, $q$SANE's first public release was on November 27, 1996, originated by David Mosberger-Tang and early collaborators.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$What is the difference between SANE backends and frontends?$q$, $q$Backends are hardware-specific drivers that communicate with individual scanner models, while frontends, such as scanimage or XSane, are the applications end users interact with to actually perform a scan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Can SANE scan over a network?$q$, $q$Yes, the saned daemon allows a scanner attached to one computer to be accessed and controlled remotely over a network.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Does SANE work with all scanners?$q$, $q$SANE supports scanners through individually maintained backend drivers, so hardware compatibility depends on whether a backend exists for a given model; support for very new consumer scanners can lag.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Where is SANE's source code hosted?$q$, $q$The sane-backends source code and issue tracker are hosted on GitLab under the sane-project namespace.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$What applications use SANE?$q$, $q$Applications like GIMP's scanner plugin, XSane, and many Linux print-and-scan utilities use SANE as their underlying scanning layer.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Linux Desktop Scanning$q$, $q$Desktop Linux users scan documents and photos using graphical frontends like XSane or GIMP's scanner plugin, both built on the SANE API.$q$, $q$Linux desktop users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Scripted and Automated Scanning$q$, $q$System administrators and developers use the scanimage command-line frontend to script batch scanning jobs on Unix and Linux servers.$q$, $q$Linux system administrators and developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Shared Network Scanning$q$, $q$Offices with a scanner attached to one Linux machine use the saned daemon to let multiple users scan remotely over the network.$q$, $q$Small office and lab environments running Linux$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full SANE API and backend driver source code","scanimage command-line frontend included","saned network scanning daemon","GPL/LGPL licensed, free to modify and redistribute"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$SANE, short for Scanner Access Now Easy, is a free, open-source API and driver framework first released on November 27, 1996 by David Mosberger-Tang and early collaborators, providing standardized scanner access across Unix and Linux systems.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$SANE separates hardware-specific backend drivers from generic frontend applications, with the command-line scanimage tool and the saned network scanning daemon included in the core sane-backends package.$q$, $q$Separately distributed graphical frontends such as XSane and xscanimage sit on top of the same API, and SANE underpins scanning support in tools like GIMP's scanner plugin across virtually every major Linux distribution.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bab3c6db-9b5a-484e-b9f3-7c8e256e957e', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SANE is free and open source, distributed under GPL and LGPL licenses, with no company, list price, or subscription plans; its source code is hosted publicly on GitLab under the sane-project namespace.$q$]::text[], 2);
